// ── Linux ─────────────────────────────────────────────────────────────────────

fn detectLinux(target: std.Target) LibcHeaders {
    return .{
        .execinfo_h = !target.abi.isMusl(),
        .sys_epoll_h = true,
        .sys_personality_h = true,
        .sys_prctl_h = true,
        .sys_signalfd_h = true,
    };
}

