    return .{
        .copyfile_h = true,
        .execinfo_h = true,
        .sys_event_h = true,
        .sys_ucred_h = true,
        .xlocale_h = true,
    };
}

// ── BSDs ──────────────────────────────────────────────────────────────────────

fn gte(os: std.Target.Os, comptime tag: std.Target.Os.Tag, ver: std.SemanticVersion) bool {
    return os.isAtLeast(tag, ver) orelse false;
}

fn detectFreeBSD(target: std.Target) LibcHeaders {
    return .{
        .execinfo_h = true,
        .sys_event_h = true,
        .sys_procctl_h = gte(target.os, .freebsd, .{ .major = 10, .minor = 1, .patch = 0 }), // https://man.freebsd.org/cgi/man.cgi?query=procctl&sektion=2
        .sys_ucred_h = true,
        .xlocale_h = true,
    };
}

